// Get pages from the first node
const pages = $('Get Active Pages').all().map(i => i.json);
const snapshots = $('Get This Week Snapshots').all().map(i => i.json);

// Build a lookup of snapshots by tracked_page_id
const snapMap = {};
for (const snap of snapshots) {
  if (!snapMap[snap.tracked_page_id]) {
    snapMap[snap.tracked_page_id] = snap;
  }
}

// Join: for each page, find its latest snapshot
const results = [];
for (const page of pages) {
  const snap = snapMap[page.id];
  if (snap) {
    results.push({
      json: {
        page_id: page.id,
        company_id: page.company_id,
        company_name: page.company_name,
        url: page.url,
        url_type: page.url_type,
        snapshot_id: snap.id,
        tracked_page_id: snap.tracked_page_id,
        text_content: snap.text_content || '',
        raw_html: snap.raw_html || snap.text_content || '',
        week_start_date: snap.week_start_date
      }
    });
  }
}

return results;

function fnv1a64(str) {
  let h1 = 0x811c9dc5 >>> 0;
  let h2 = 0xcbf29ce4 >>> 0;
  for (let i = 0; i < str.length; i++) {
    const c = str.charCodeAt(i);
    h1 = Math.imul(h1 ^ c, 0x01000193) >>> 0;
    h2 = Math.imul(h2 ^ (c >> 8 | c), 0x01000193) >>> 0;
  }
  return h2.toString(16).padStart(8, '0') + h1.toString(16).padStart(8, '0');
}

const input = $input.first().json;
const prev = $('Merge Pages + Snapshots').first().json;
let text = input.content?.[0]?.text || '';
const fenceMatch = text.match(/```(?:\w*)\s*([\s\S]*?)```/);
if (fenceMatch) text = fenceMatch[1].trim();
const hash = fnv1a64(text);
return [{json: {
  tracked_page_id: prev.tracked_page_id,
  company_id: prev.company_id,
  company_name: prev.company_name,
  url_type: prev.url_type,
  week_start_date: prev.week_start_date,
  extracted_copy: text,
  copy_hash: hash
}}];

// After all pages processed, gather all narrative snapshots for drift analysis
const items = $input.all().map(i => i.json);
// Group by company
const byCompany = {};
for (const item of items) {
  const key = item.company_id || item.tracked_page_id;
  if (!byCompany[key]) byCompany[key] = { items: [], company_name: '' };
  if (Array.isArray(item)) {
    item.forEach(r => {
      byCompany[r.company_id] = byCompany[r.company_id] || {items:[], company_name: r.company_name || ''};
      byCompany[r.company_id].items.push(r);
    });
  } else {
    byCompany[key].items.push(item);
    byCompany[key].company_name = item.company_name || byCompany[key].company_name;
  }
}
// Pass all upserted snapshots forward as single item for next phase
return [{json: {phase: 'drift_detection', snapshot_count: items.length, message: 'Ready for drift detection'}}];

const snapshots = $input.all().map(i => i.json);
// Group by company_id
const byCompany = {};
for (const s of snapshots) {
  if (!byCompany[s.company_id]) byCompany[s.company_id] = [];
  byCompany[s.company_id].push(s);
}
const results = [];
const allCompanyCopy = [];
for (const [companyId, snaps] of Object.entries(byCompany)) {
  snaps.sort((a,b) => b.week_start_date.localeCompare(a.week_start_date));
  const current = snaps[0];
  const previous = snaps.length > 1 ? snaps[1] : null;
  allCompanyCopy.push({company_id: companyId, current_copy: current.extracted_copy, week: current.week_start_date});
  if (previous && current.copy_hash !== previous.copy_hash) {
    results.push({json: {
      company_id: companyId,
      week_start_date: current.week_start_date,
      current_copy: current.extracted_copy,
      previous_copy: previous.extracted_copy,
      changed: true
    }});
  } else {
    results.push({json: {
      company_id: companyId,
      week_start_date: current.week_start_date,
      current_copy: current.extracted_copy,
      previous_copy: previous ? previous.extracted_copy : '',
      changed: false
    }});
  }
}
// Store all company copy for category analysis as last item
results.push({json: {
  _is_category_data: true,
  all_company_copy: allCompanyCopy,
  week_start_date: snapshots[0]?.week_start_date || new Date().toISOString().slice(0,10)
}});
return results;

const raw = $input.first().json;
const prev = $('Filter: Has Drift?').first().json;
let text = raw.content?.[0]?.text || '{}';
const fm = text.match(/```(?:\w*)\s*([\s\S]*?)```/);
if (fm) text = fm[1].trim();
let c;
try { c = JSON.parse(text); } catch(e) { c = {drift_detected: false}; }
return [{json: {
  company_id: prev.company_id,
  week_start_date: prev.week_start_date,
  drift_detected: c.drift_detected || false,
  drift_from: c.drift_from || null,
  drift_to: c.drift_to || null,
  drift_direction: c.drift_direction || null,
  scope: 'single_company',
  gtm_implication: c.gtm_implication || null,
  severity: c.severity || 1,
  raw_llm_response: c
}}];

const items = $input.all();
const results = [];
for (const item of items) {
  const d = item.json;
  results.push({
    json: {
      tracked_page_id: d.tracked_page_id || d.page_id,
      company_id: d.company_id,
      company_name: d.company_name,
      url_type: d.url_type,
      week_start_date: d.week_start_date || '2026-01-26',
      extracted_copy: d.extracted_copy || '',
      copy_hash: d.copy_hash || ''
    }
  });
}
return results;

// Gather all drift results from the Parse Drift Result step
let drifts = [];
try {
  drifts = $('Parse Drift Result').all().map(i => i.json);
} catch(e) {}

if (drifts.length === 0) {
  return [{json: {skip: true, reason: 'no_drifts_detected', company_ids_csv: ''}}];
}

const companyIds = [...new Set(drifts.map(d => d.company_id).filter(Boolean))];
return [{json: {
  skip: false,
  this_week_drifts: drifts,
  company_ids: companyIds,
  company_ids_csv: companyIds.join(',')
}}];

const driftData = $('Collect Drift Data').first().json;
const existingArcs = $('Fetch Active Arcs').all().map(i => i.json);
const recentDrifts = $('Fetch Recent Drifts').all().map(i => i.json);

return [{json: {
  this_week_drifts: driftData.this_week_drifts || [],
  existing_arcs: Array.isArray(existingArcs[0]) ? existingArcs[0] : existingArcs,
  recent_drifts: Array.isArray(recentDrifts[0]) ? recentDrifts[0] : recentDrifts,
  company_ids: driftData.company_ids || []
}}];

const raw = $input.first().json;
let text = raw.content?.[0]?.text || '{}';
const fm = text.match(/```(?:\w*)\s*([\s\S]*?)```/);
if (fm) text = fm[1].trim();

let parsed;
try { parsed = JSON.parse(text); } catch(e) {
  return [{json: {error: true, arc_operations: [], raw: text.slice(0, 500)}}];
}

const ops = parsed.arc_operations || [];
// Emit each operation as a separate item for HTTP Request processing
if (ops.length === 0) {
  return [{json: {error: false, arc_operations: [], no_ops: true}}];
}

// Return all ops as a single item for the upsert code to process
const prevData = $('Merge Arc Context').first().json;
return [{json: {
  error: false,
  arc_operations: ops,
  existing_arcs: prevData.existing_arcs || [],
  company_ids: prevData.company_ids || []
}}];

const parsedOps = $('Parse Arc Operations').first().json;
const ops = parsedOps.arc_operations || [];
const createdArcs = $('Upsert Arcs via RPC').all().map(i => i.json);
const flatCreated = Array.isArray(createdArcs[0]) ? createdArcs[0] : createdArcs;

const edges = [];
let createIdx = 0;

for (const op of ops) {
  let arcId = op.arc_id;
  if (op.operation === 'create' && flatCreated[createIdx]) {
    arcId = flatCreated[createIdx].id;
    createIdx++;
  }
  if (arcId && op.edge) {
    edges.push({
      arc_id: arcId,
      signal_source: op.edge.signal_source || 'narrative_drift',
      source_id: op.edge.source_id || '00000000-0000-0000-0000-000000000000',
      week_start_date: op.edge.week_start_date || new Date().toISOString().slice(0,10),
      edge_label: op.edge.edge_label || 'origin',
      llm_reasoning: op.edge.llm_reasoning || null,
      evidence_weight: op.edge.evidence_weight || 'medium',
      page_type: op.edge.page_type || null
    });
  }
}

if (edges.length === 0) {
  return [{json: {edges: [], arc_results: ops.map(o => ({op: o.operation, company_id: o.company_id, title: o.arc_title}))}}];
}

return [{json: {edges: edges, arc_results: ops.map((o, i) => ({op: o.operation, arc_id: o.arc_id || (flatCreated[i]?.id), company_id: o.company_id, title: o.arc_title}))}}];

const raw = $input.first().json;
let text = raw.content?.[0]?.text || '{}';
const fm = text.match(/```(?:\w*)\s*([\s\S]*?)```/);
if (fm) text = fm[1].trim();

let parsed;
try { parsed = JSON.parse(text); } catch(e) {
  return [{json: {convergences: [], error: true}}];
}

const convergences = (parsed.convergences || []).filter(c => c.company_ids && c.company_ids.length >= 2);

const weekDate = new Date();
const day = weekDate.getDay();
const diff = weekDate.getDate() - day + (day === 0 ? -6 : 1);
weekDate.setDate(diff);
const weekStr = weekDate.toISOString().slice(0,10);

// Format for batch insert
const records = convergences.map(c => ({
  convergence_theme: c.convergence_theme || 'Unknown',
  week_detected: weekStr,
  company_ids: c.company_ids,
  arc_ids: c.arc_ids || [],
  severity: c.severity || 1,
  summary: c.summary || null,
  corroboration_score: c.corroboration_score || 'weak',
  alternative_explanation: c.alternative_explanation || null,
  confidence_level: c.confidence_level || 'low'
}));

return [{json: {convergence_records: records, count: records.length}}];
